/*****************************************************************************
 * test_kernel_v2.c — vsim pipeline benchmark for nn_mat_mult_kernel_s8_offset_v2
 *
 * Exercises the vd4dots GEMM kernel with parameters matching the conv
 * HWC_s8_s8_s8_asym_bias_any workload (out_tensor_ch=16, col=144).
 *
 * Build for vsim bare-metal (see Makefile), then run with konata.py
 * for pipeline analysis.
 ****************************************************************************/
#include <stdio.h>
#include <stdint.h>
#include <string.h>

/* Prototype — defined in libnn.a */
extern int8_t* nn_mat_mult_kernel_s8_offset_v2(
    const int8_t  *input_a,
    const int8_t  *input_b,
    const int32_t  out_tensor_ch,
    const int32_t *out_shift,
    const int32_t *out_scale,
    const int32_t  in_offset,
    const int32_t  out_offset,
    const int32_t  act_min,
    const int32_t  act_max,
    const int32_t  num_col_a,
    const int32_t *contri_buf,
    int8_t        *out);

/*
 * Parameters matching the real conv layer:
 *   out_tensor_ch = 16   (output channels — small, triggers vd4dots path)
 *   num_col_a     = 144  (in_ch * ker_h * ker_w = 16 * 3 * 3)
 *   num_rows      = 8    (batch of output pixels processed per GEMM call)
 */
#define OUT_CH   16
#define COL      144
#define NUM_ROWS 8

/* Static buffers (global to avoid stack overflow in bare-metal) */
static int8_t  im2col_buf[NUM_ROWS * COL];      /* input_a: im2col rows */
static int8_t  weight_buf[OUT_CH * COL];         /* input_b: weight matrix */
static int8_t  output_buf[NUM_ROWS * OUT_CH];    /* output */
static int32_t out_shift[OUT_CH];
static int32_t out_scale[OUT_CH];
static int32_t contri_buf[OUT_CH];               /* bias contribution */

int main(void)
{
    /* Initialize buffers with simple deterministic data */
    for (int i = 0; i < NUM_ROWS * COL; i++)
        im2col_buf[i] = (int8_t)((i * 7 + 3) & 0x7F);

    for (int i = 0; i < OUT_CH * COL; i++)
        weight_buf[i] = (int8_t)((i * 13 + 5) & 0x7F);

    for (int i = 0; i < OUT_CH; i++) {
        out_shift[i] = -10;         /* typical shift: negative means right-shift */
        out_scale[i] = 1234567890;  /* typical requantize multiplier */
        contri_buf[i] = 100 + i;    /* bias + input_offset contribution */
    }

    memset(output_buf, 0, sizeof(output_buf));

    printf("=== nn_mat_mult_kernel_s8_offset_v2 pipeline test ===\n");
    printf("out_ch=%d  col=%d  rows=%d\n", OUT_CH, COL, NUM_ROWS);

    /* Call the kernel — this is the hot function we want to profile */
    int8_t *result = nn_mat_mult_kernel_s8_offset_v2(
        im2col_buf,     /* input_a */
        weight_buf,     /* input_b */
        OUT_CH,         /* out_tensor_ch */
        out_shift,
        out_scale,
        0,              /* in_offset (unused in v2, absorbed into contri_buf) */
        0,              /* out_offset */
        -128,           /* act_min */
        127,            /* act_max */
        COL,            /* num_col_a */
        contri_buf,
        output_buf);

    /* Verify something was written */
    int nonzero = 0;
    for (int i = 0; i < NUM_ROWS * OUT_CH; i++) {
        if (output_buf[i] != 0) nonzero++;
    }

    printf("result ptr offset: %ld\n", (long)(result - output_buf));
    printf("nonzero outputs: %d / %d\n", nonzero, NUM_ROWS * OUT_CH);
    printf("sample: [%d %d %d %d ...]\n",
           output_buf[0], output_buf[1], output_buf[2], output_buf[3]);

    return 0;
}

