    const int8_t *input_a,    /* im2col: NUM_ROWS rows × COL cols */
    const int8_t *input_b,    /* weights: OUT_CH rows × COL cols */
    int32_t *output,          /* accumulator output */
    int num_rows,
    int num_ch,
    int col)
{
