                "vsetvli t0, %[col], e32, m4, tu, mu\n\t"
                "vand.vi v0, v0, 0\n\t"
                "vand.vi v4, v4, 0\n\t"
                "vand.vi v8, v8, 0\n\t"
                "vand.vi v12, v12, 0\n\t"

