                "mv t1, %[col]\n\t"          /* remaining = col */
                "vsetvli zero, zero, e8, m4, tu, mu\n\t"
                "csrr t6, vlenb\n\t"         /* t6 = VLEN/8 */
                "slli t6, t6, 2\n\t"         /* t6 = VLMAX for e8,m4 */

